import { useEffect, useState } from 'react';
import Layout from '../components/Layout';
import { bolgeAPI } from '../api';

export default function BolgeStoklar() {
  const [stoklar, setStoklar] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  useEffect(() => {
    bolgeAPI.getStoklar().then(r => setStoklar(r.data)).catch(() => {}).finally(() => setLoading(false));
  }, []);

  const filtered = stoklar.filter(s =>
    s.urun_adi?.toLowerCase().includes(search.toLowerCase()) ||
    s.merkez_adi?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <Layout title="Bölge Stok Durumu">
      <div className="card">
        <div className="card-header">
          <div className="card-title">Stoklar ({filtered.length})</div>
          <input className="form-control" style={{ width: 200 }} placeholder="🔍 Ara..." value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        {loading ? <div className="loading"><div className="spinner" /></div> : (
          <div className="table-wrapper">
            <table>
              <thead>
                <tr><th>Ürün</th><th>Marka</th><th>Kategori</th><th>Adet</th><th>Merkez</th></tr>
              </thead>
              <tbody>
                {filtered.map(s => (
                  <tr key={s.id}>
                    <td><strong>{s.urun_adi}</strong></td>
                    <td>{s.marka || '—'}</td>
                    <td>{s.kategori ? <span className="badge badge-neutral">{s.kategori}</span> : '—'}</td>
                    <td style={{ fontFamily: 'IBM Plex Mono', fontWeight: 700, color: s.adet <= 10 ? 'var(--danger)' : 'var(--accent3)' }}>{s.adet} <span style={{ color: 'var(--text3)', fontSize: 11 }}>{s.birim}</span></td>
                    <td style={{ fontSize: 12, color: 'var(--text2)' }}>{s.merkez_adi}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </Layout>
  );
}
